import { describe, expect, it, vi, beforeEach } from "vitest";
let mockRequestInfo;
vi.mock("./requestInfo/worker", () => ({
    get requestInfo() {
        return mockRequestInfo;
    },
}));
import { serverAction, serverQuery, registerServerFunctionWrap, __resetServerFunctionWrap, } from "./server";
describe("registerServerFunctionWrap", () => {
    beforeEach(() => {
        __resetServerFunctionWrap();
        mockRequestInfo = {
            request: new Request("https://test.example/"),
            ctx: {},
        };
    });
    it("wraps serverAction handlers", async () => {
        const wrapSpy = vi.fn((fn, args, _type) => fn(...args));
        registerServerFunctionWrap(wrapSpy);
        const action = serverAction(async function createThing(name) {
            return `created ${name}`;
        });
        const result = await action("foo");
        expect(wrapSpy).toHaveBeenCalledOnce();
        expect(wrapSpy.mock.calls[0][2]).toBe("action");
        expect(result).toBe("created foo");
    });
    it("wraps serverQuery handlers", async () => {
        const wrapSpy = vi.fn((fn, args, _type) => fn(...args));
        registerServerFunctionWrap(wrapSpy);
        const query = serverQuery(async function getThings() {
            return [1, 2, 3];
        });
        const result = await query();
        expect(wrapSpy).toHaveBeenCalledOnce();
        expect(wrapSpy.mock.calls[0][2]).toBe("query");
        expect(result).toEqual([1, 2, 3]);
    });
    it("passes the main function and args to the wrapper", async () => {
        const wrapSpy = vi.fn((fn, args, _type) => fn(...args));
        registerServerFunctionWrap(wrapSpy);
        const action = serverAction(async function multiply(a, b) {
            return a * b;
        });
        await action(3, 7);
        const [fn, args] = wrapSpy.mock.calls[0];
        expect(fn.name).toBe("multiply");
        expect(args).toEqual([3, 7]);
    });
    it("interruptors run outside the wrapper", async () => {
        const order = [];
        registerServerFunctionWrap((fn, args, _type) => {
            order.push("wrap:start");
            const result = fn(...args);
            order.push("wrap:end");
            return result;
        });
        const interruptor = async () => {
            order.push("interruptor");
        };
        const action = serverAction([
            interruptor,
            async function doWork() {
                order.push("handler");
                return "done";
            },
        ]);
        await action();
        expect(order).toEqual([
            "interruptor",
            "wrap:start",
            "handler",
            "wrap:end",
        ]);
    });
    it("wrapper is not called when an interruptor short-circuits", async () => {
        const wrapSpy = vi.fn((fn, args, _type) => fn(...args));
        registerServerFunctionWrap(wrapSpy);
        const action = serverAction([
            async () => new Response("blocked", { status: 403 }),
            async function neverCalled() {
                return "nope";
            },
        ]);
        const result = await action();
        expect(wrapSpy).not.toHaveBeenCalled();
        expect(result).toBeInstanceOf(Response);
    });
    it("replaces the wrapper if called more than once", async () => {
        const first = vi.fn((fn, args, _type) => fn(...args));
        const second = vi.fn((fn, args, _type) => fn(...args));
        registerServerFunctionWrap(first);
        registerServerFunctionWrap(second);
        const action = serverAction(async function run() {
            return "ok";
        });
        await action();
        expect(first).not.toHaveBeenCalled();
        expect(second).toHaveBeenCalledOnce();
    });
    it("without registration, handlers work normally", async () => {
        const action = serverAction(async function echo(msg) {
            return msg;
        });
        const result = await action("hello");
        expect(result).toBe("hello");
    });
    it("wrapper can transform the return value", async () => {
        registerServerFunctionWrap(async (fn, args, _type) => {
            const result = await fn(...args);
            return { wrapped: true, result };
        });
        const action = serverAction(async function getValue() {
            return 42;
        });
        const result = await action();
        expect(result).toEqual({ wrapped: true, result: 42 });
    });
    it("works with array-style serverAction (interruptors + handler)", async () => {
        const wrapSpy = vi.fn((fn, args, _type) => fn(...args));
        registerServerFunctionWrap(wrapSpy);
        const action = serverAction([
            async ({ ctx }) => {
                ctx.authed = true;
            },
            async function save(data) {
                return `saved ${data}`;
            },
        ]);
        const result = await action("test");
        expect(result).toBe("saved test");
        expect(wrapSpy).toHaveBeenCalledOnce();
        const [fn] = wrapSpy.mock.calls[0];
        expect(fn.name).toBe("save");
    });
});

// context(justinvdm, 2026-04-06): Extracted from rscActionHandler() for testability.
// The real getServerModuleExport and decodeReply require the react-server environment
// (virtual module lookup, react-server-dom-webpack), so we accept them as injected
// dependencies. worker.ts passes the real implementations; tests pass fakes.
// context(justinvdm, 2026-04-20): Origin validation for non-GET action requests.
// Method enforcement alone does not distinguish a legitimate same-origin POST
// from a POST driven by a same-site sibling origin (e.g. sibling subdomain,
// another localhost port). SameSite=Lax cookies are attached in both cases, and
// the action request's Content-Type is CORS-safelisted, so no preflight fires.
// We require the request's Origin header to match the app's own origin, unless
// the caller origin is listed in allowedOrigins.
function validateSameOrigin(req, allowedOrigins) {
    const origin = req.headers.get("Origin");
    if (!origin) {
        return {
            valid: false,
            response: new Response("Missing Origin header", { status: 403 }),
        };
    }
    const selfOrigin = new URL(req.url).origin;
    if (origin === selfOrigin) {
        return { valid: true };
    }
    if (allowedOrigins && allowedOrigins.includes(origin)) {
        return { valid: true };
    }
    return {
        valid: false,
        response: new Response("Origin not allowed", { status: 403 }),
    };
}
export async function rscActionHandler(req, { getServerModuleExport, decodeReply, allowedOrigins }) {
    const url = new URL(req.url);
    const contentType = req.headers.get("content-type");
    // context(justinvdm, 2026-04-20): Enforce Origin/Host match for non-GET action
    // requests. GET (serverQuery) is expected to be idempotent and is not subject
    // to this check.
    if (req.method !== "GET") {
        const originCheck = validateSameOrigin(req, allowedOrigins);
        if (!originCheck.valid) {
            return originCheck.response;
        }
    }
    let args = [];
    if (req.method === "GET") {
        const argsParam = url.searchParams.get("args");
        if (argsParam) {
            args = JSON.parse(argsParam);
        }
    }
    else {
        const data = contentType?.startsWith("multipart/form-data")
            ? await req.formData()
            : await req.text();
        args = (await decodeReply(data, null));
    }
    const actionId = url.searchParams.get("__rsc_action_id");
    if (import.meta.env.VITE_IS_DEV_SERVER && actionId === "__rsc_hot_update") {
        return null;
    }
    const action = await getServerModuleExport(actionId);
    if (typeof action !== "function") {
        throw new Error(`Action ${actionId} is not a function`);
    }
    // context(justinvdm, 2026-04-06): Validate the declared HTTP method before
    // invocation. serverAction() attaches .method = "POST" at creation time via
    // createServerFunction(), serverQuery() attaches "GET". Functions without
    // .method default to POST to match serverAction() semantics.
    const actionMethod = action.method ?? "POST";
    if (actionMethod !== req.method) {
        return new Response(`Method ${req.method} is not allowed for this action. Allowed: ${actionMethod}.`, {
            status: 405,
            headers: { Allow: actionMethod },
        });
    }
    return action(...args);
}

import { Lang, Lang as SgLang, parse as sgParse } from "@ast-grep/napi";
import debug from "debug";
import MagicString from "magic-string";
import path from "path";
import { findExports } from "./findSpecifiers.mjs";
import { hasDirective } from "./hasDirective.mjs";
const log = debug("rwsdk:vite:transform-server-functions");
export const findExportedFunctions = (code, normalizedId) => {
    return findExportInfo(code, normalizedId).localFunctions;
};
export const findExportInfo = (code, normalizedId) => {
    process.env.VERBOSE && log("Finding exported functions in source file");
    const localFunctions = new Set();
    const reExports = [];
    const exportInfos = findExports(normalizedId || "file.ts", code, log);
    for (const exportInfo of exportInfos) {
        if (exportInfo.isReExport && exportInfo.moduleSpecifier) {
            // For re-exports, we need to determine the original name by parsing the code
            // For "export { default as multiply }", we want localName="multiply", originalName="default"
            // For "export { sum }", we want localName="sum", originalName="sum"
            let originalName = exportInfo.name;
            // Check if this is a default re-export with alias
            if (exportInfo.isDefault && exportInfo.alias) {
                originalName = "default";
            }
            reExports.push({
                localName: exportInfo.name,
                originalName: originalName,
                moduleSpecifier: exportInfo.moduleSpecifier,
            });
            process.env.VERBOSE &&
                log("Found re-exported function: %s (original: %s) from %s", exportInfo.name, originalName, exportInfo.moduleSpecifier);
        }
        else {
            localFunctions.add(exportInfo.name);
            process.env.VERBOSE &&
                log("Found exported function: %s", exportInfo.name);
        }
    }
    log("Found %d local functions: %O", localFunctions.size, Array.from(localFunctions));
    log("Found %d re-exports: %O", reExports.length, reExports.map((r) => `${r.localName} from ${r.moduleSpecifier}`));
    return { localFunctions, reExports };
};
// Helper function to find default function names using ast-grep
function findDefaultFunctionName(code, normalizedId) {
    const ext = path.extname(normalizedId).toLowerCase();
    const lang = ext === ".tsx" || ext === ".jsx" ? Lang.Tsx : SgLang.TypeScript;
    try {
        const root = sgParse(lang, code);
        const matches = root
            .root()
            .findAll("export default function $NAME($$$) { $$$ }");
        if (matches.length > 0) {
            const nameCapture = matches[0].getMatch("NAME");
            return nameCapture?.text() || null;
        }
    }
    catch (err) {
        process.env.VERBOSE && log("Error finding default function name: %O", err);
    }
    return null;
}
// Helper function to check if there's a default export (not re-export)
function hasDefaultExport(code, normalizedId) {
    const ext = path.extname(normalizedId).toLowerCase();
    const lang = ext === ".tsx" || ext === ".jsx" ? Lang.Tsx : SgLang.TypeScript;
    try {
        const root = sgParse(lang, code);
        // Check for any export default statements
        const patterns = [
            "export default function $$$",
            "export default function($$$) { $$$ }",
            "export default $$$",
        ];
        for (const pattern of patterns) {
            const matches = root.root().findAll(pattern);
            if (matches.length > 0) {
                return true;
            }
        }
    }
    catch (err) {
        process.env.VERBOSE && log("Error checking for default export: %O", err);
    }
    return false;
}
export const transformServerFunctions = (code, normalizedId, environment, serverFiles) => {
    if (!serverFiles.has(normalizedId) && !hasDirective(code, "use server")) {
        return;
    }
    process.env.VERBOSE &&
        log("Processing 'use server' module: normalizedId=%s, environment=%s", normalizedId, environment);
    if (environment === "ssr" || environment === "client") {
        process.env.VERBOSE &&
            log(`Transforming for ${environment} environment: normalizedId=%s`, normalizedId);
        const exportInfo = findExportInfo(code, normalizedId);
        const reExportNames = new Set(exportInfo.reExports.map((r) => r.localName));
        const allExports = new Set(Array.from(exportInfo.localFunctions).filter((name) => !reExportNames.has(name)));
        // Check for default function exports that should also be named exports
        const defaultFunctionName = findDefaultFunctionName(code, normalizedId);
        if (defaultFunctionName) {
            allExports.add(defaultFunctionName);
        }
        // Generate completely new code for SSR
        const s = new MagicString("");
        const hasDefExport = hasDefaultExport(code, normalizedId);
        if (allExports.size > 0 || hasDefExport) {
            if (environment === "ssr") {
                s.append('import { createServerReference } from "rwsdk/__ssr";\n\n');
            }
            else {
                s.append('import { createServerReference } from "rwsdk/client";\n\n');
            }
        }
        for (const reExport of exportInfo.reExports) {
            const reExportStatement = reExport.originalName === "default"
                ? `export { default as ${reExport.localName} } from ${JSON.stringify(reExport.moduleSpecifier)};\n`
                : reExport.originalName === reExport.localName
                    ? `export { ${reExport.originalName} } from ${JSON.stringify(reExport.moduleSpecifier)};\n`
                    : `export { ${reExport.originalName} as ${reExport.localName} } from ${JSON.stringify(reExport.moduleSpecifier)};\n`;
            s.append(reExportStatement);
            log(`Preserved ${environment} re-export for function: %s (original: %s) from %s in normalizedId=%s`, reExport.localName, reExport.originalName, reExport.moduleSpecifier, normalizedId);
        }
        if (exportInfo.reExports.length > 0 && allExports.size > 0) {
            s.append("\n");
        }
        const ext = path.extname(normalizedId).toLowerCase();
        const lang = ext === ".tsx" || ext === ".jsx" ? Lang.Tsx : SgLang.TypeScript;
        const root = sgParse(lang, code);
        for (const name of allExports) {
            if (name !== "default" && name !== defaultFunctionName) {
                let method;
                let source = "action";
                // Try to find if this export is a serverQuery or serverAction call to extract the method
                const patterns = [
                    `export const ${name} = serverQuery($$$, { method: "$METHOD" })`,
                    `export const ${name} = serverQuery($$$)`,
                    `export const ${name} = serverAction($$$)`,
                ];
                for (const pattern of patterns) {
                    const matches = root.root().findAll(pattern);
                    if (matches.length > 0) {
                        if (pattern.includes("serverQuery")) {
                            const methodMatch = matches[0].getMatch("METHOD");
                            method = methodMatch ? methodMatch.text() : "GET";
                            source = "query";
                        }
                        else if (pattern.includes("serverAction")) {
                            method = "POST";
                            source = "action";
                        }
                        break;
                    }
                }
                let extraArgs = "";
                if (source === "query") {
                    extraArgs = `, ${JSON.stringify(method ?? "GET")}, "query"`;
                }
                else if (method !== undefined) {
                    extraArgs = `, ${JSON.stringify(method)}`;
                }
                s.append(`export let ${name} = createServerReference(${JSON.stringify(normalizedId)}, ${JSON.stringify(name)}${extraArgs});\n`);
                log(`Added ${environment} server reference for function: %s (method: %s, source: %s) in normalizedId=%s`, name, method || "default", source, normalizedId);
            }
        }
        // Check for default export in the actual module (not re-exports)
        if (hasDefExport) {
            let method;
            let source = "action";
            const patterns = [
                `export default serverQuery($$$, { method: "$METHOD" })`,
                `export default serverQuery($$$)`,
                `export default serverAction($$$)`,
            ];
            for (const pattern of patterns) {
                const matches = root.root().findAll(pattern);
                if (matches.length > 0) {
                    if (pattern.includes("serverQuery")) {
                        const methodMatch = matches[0].getMatch("METHOD");
                        method = methodMatch ? methodMatch.text() : "GET";
                        source = "query";
                    }
                    else if (pattern.includes("serverAction")) {
                        method = "POST";
                        source = "action";
                    }
                    break;
                }
            }
            let extraArgs = "";
            if (source === "query") {
                extraArgs = `, ${JSON.stringify(method ?? "GET")}, "query"`;
            }
            else if (method !== undefined) {
                extraArgs = `, ${JSON.stringify(method)}`;
            }
            s.append(`\nexport default createServerReference(${JSON.stringify(normalizedId)}, "default"${extraArgs});\n`);
            log(`Added ${environment} server reference for default export (method: %s, source: %s) in normalizedId=%s`, method || "default", source, normalizedId);
        }
        process.env.VERBOSE &&
            log(`${environment} transformation complete for normalizedId=%s`, normalizedId);
        return {
            code: s.toString(),
            map: s.generateMap({
                source: normalizedId,
                includeContent: true,
                hires: true,
            }),
        };
    }
    else if (environment === "worker") {
        process.env.VERBOSE &&
            log("Transforming for worker environment: normalizedId=%s", normalizedId);
        const exportInfo = findExportInfo(code, normalizedId);
        const s = new MagicString(code);
        // Remove "use server" directive first
        const directiveRegex = /^(\s*)(['"]use server['"])\s*;?\s*$/gm;
        let match;
        while ((match = directiveRegex.exec(code)) !== null) {
            const start = match.index;
            const end = match.index + match[0].length;
            s.remove(start, end);
            process.env.VERBOSE &&
                log("Removed 'use server' directive from normalizedId=%s", normalizedId);
            break; // Only remove the first one
        }
        // Add imports at the very beginning
        let importsToAdd = [];
        // Add imports for re-exported functions so they exist in scope
        for (const reExport of exportInfo.reExports) {
            // Fix the import statement - the originalName is what we import, localName is the alias
            const importStatement = reExport.originalName === "default"
                ? `import { default as ${reExport.localName} } from "${reExport.moduleSpecifier}";`
                : reExport.originalName === reExport.localName
                    ? `import { ${reExport.originalName} } from "${reExport.moduleSpecifier}";`
                    : `import { ${reExport.originalName} as ${reExport.localName} } from "${reExport.moduleSpecifier}";`;
            importsToAdd.push(importStatement);
            log("Added import for re-exported function: %s from %s in normalizedId=%s", reExport.localName, reExport.moduleSpecifier, normalizedId);
        }
        // Add registerServerReference import
        importsToAdd.push('import { registerServerReference } from "rwsdk/worker";');
        // Add imports - position depends on whether file starts with block comment
        if (importsToAdd.length > 0) {
            const trimmedCode = code.trim();
            if (trimmedCode.startsWith("/*")) {
                // Find the end of the block comment
                const blockCommentEnd = code.indexOf("*/");
                if (blockCommentEnd !== -1) {
                    // Insert after the block comment
                    const insertPos = blockCommentEnd + 2;
                    // Find the next newline after the block comment
                    const nextNewline = code.indexOf("\n", insertPos);
                    const actualInsertPos = nextNewline !== -1 ? nextNewline + 1 : insertPos;
                    s.appendLeft(actualInsertPos, importsToAdd.join("\n") + "\n");
                }
                else {
                    s.prepend(importsToAdd.join("\n") + "\n");
                }
            }
            else {
                // No block comment at start, add at beginning
                s.prepend(importsToAdd.join("\n") + "\n");
            }
        }
        // Handle default export renaming if present
        const hasDefExport = hasDefaultExport(code, normalizedId);
        if (hasDefExport) {
            // Find and rename default function export using ast-grep
            const ext = path.extname(normalizedId).toLowerCase();
            const lang = ext === ".tsx" || ext === ".jsx" ? Lang.Tsx : SgLang.TypeScript;
            try {
                const root = sgParse(lang, code);
                // Handle named default function: export default function myFunc() {}
                const namedMatches = root
                    .root()
                    .findAll("export default function $NAME($$$) { $$$ }");
                if (namedMatches.length > 0) {
                    const match = namedMatches[0];
                    const range = match.range();
                    const funcName = match.getMatch("NAME")?.text();
                    if (funcName) {
                        // Replace "export default function myFunc" with "function __defaultServerFunction__"
                        const newText = match
                            .text()
                            .replace(`export default function ${funcName}`, "function __defaultServerFunction__");
                        s.overwrite(range.start.index, range.end.index, newText);
                        s.append("\nexport default __defaultServerFunction__;\n");
                    }
                }
                else {
                    // Handle anonymous default function: export default function() {}
                    const anonMatches = root
                        .root()
                        .findAll("export default function($$$) { $$$ }");
                    if (anonMatches.length > 0) {
                        const match = anonMatches[0];
                        const range = match.range();
                        const newText = match
                            .text()
                            .replace("export default function", "function __defaultServerFunction__");
                        s.overwrite(range.start.index, range.end.index, newText);
                        s.append("\nexport default __defaultServerFunction__;\n");
                    }
                    else {
                        const predefinedMatches = root
                            .root()
                            .findAll("export default $NAME");
                        if (predefinedMatches.length > 0) {
                            const match = predefinedMatches[0];
                            const nameCapture = match.getMatch("NAME")?.text();
                            if (nameCapture) {
                                s.append(`const __defaultServerFunction__ = ${nameCapture};\n`);
                            }
                        }
                    }
                }
            }
            catch (err) {
                process.env.VERBOSE &&
                    log("Error processing default function: %O", err);
            }
        }
        // Add registration calls at the end
        let registrationCalls = [];
        const registeredFunctions = new Set(); // Track to avoid duplicates
        if (hasDefExport) {
            registrationCalls.push(`registerServerReference(__defaultServerFunction__, ${JSON.stringify(normalizedId)}, "default")`);
            registeredFunctions.add("default");
            log("Registered worker server reference for default export in normalizedId=%s", normalizedId);
        }
        // Register local functions
        const defaultFunctionName = findDefaultFunctionName(code, normalizedId);
        for (const name of exportInfo.localFunctions) {
            if (name === "__defaultServerFunction__" ||
                name === "default" ||
                name === defaultFunctionName)
                continue;
            // Skip if already registered
            if (registeredFunctions.has(name))
                continue;
            registrationCalls.push(`registerServerReference(${name}, ${JSON.stringify(normalizedId)}, ${JSON.stringify(name)})`);
            registeredFunctions.add(name);
            log("Registered worker server reference for local function: %s in normalizedId=%s", name, normalizedId);
        }
        // Register re-exported functions
        for (const reExport of exportInfo.reExports) {
            // Skip if already registered
            if (registeredFunctions.has(reExport.localName))
                continue;
            registrationCalls.push(`registerServerReference(${reExport.localName}, ${JSON.stringify(normalizedId)}, ${JSON.stringify(reExport.localName)})`);
            registeredFunctions.add(reExport.localName);
            log("Registered worker server reference for re-exported function: %s in normalizedId=%s", reExport.localName, normalizedId);
        }
        if (registrationCalls.length > 0) {
            s.append(registrationCalls.join("\n") + "\n");
        }
        process.env.VERBOSE &&
            log("Worker transformation complete for normalizedId=%s", normalizedId);
        return {
            code: s.toString(),
            map: s.generateMap({
                source: normalizedId,
                includeContent: true,
                hires: true,
            }),
        };
    }
    process.env.VERBOSE &&
        log("No transformation applied for environment=%s, normalizedId=%s", environment, normalizedId);
};

