"use server";

import { serverAction } from "rwsdk/worker";

export type Todo = {
  id: string;
  title: string;
};

const todos: Todo[] = [];

export const getTodos = (): Todo[] => {
  return [...todos];
};

export const resetTodos = (): void => {
  todos.length = 0;
};

export const addTodo = serverAction(async (title: string) => {
  const id = crypto.randomUUID();
  todos.push({ id, title });
  return { id, title };
});

export const deleteTodo = serverAction(async (id: string) => {
  const index = todos.findIndex((t) => t.id === id);
  if (index !== -1) {
    todos.splice(index, 1);
  }
});

import { getTodos, addTodo, deleteTodo } from "./todos.actions";

export const Todos = async () => {
  const todos = getTodos();

  return (
    <div>
      <h1>Todo List</h1>
      <ul>
        {todos.map((todo) => (
          <li key={todo.id} data-testid="todo-item">
            <span>{todo.title}</span>
            <form action={deleteTodo} method="POST" style={{ display: "inline" }}>
              <input type="hidden" name="id" value={todo.id} />
              <button type="submit">Delete</button>
            </form>
          </li>
        ))}
      </ul>
      <form action={addTodo} method="POST">
        <input name="title" type="text" placeholder="Enter a todo..." />
        <button type="submit">Add Todo</button>
      </form>
    </div>
  );
};

